@api.model_create_multi
def create(self, vals_list):
    for vals in vals_list:
        if vals.get('name', _('New')) == _('New'):
            seq_date = fields.Datetime.context_timestamp(self, fields.Datetime.now())
            vals['name'] = self.env['ir.sequence'].next_by_code(
                'sale.order', sequence_date=seq_date,
            ) or _('New')
    return super().create(vals_list)

def write(self, vals):
    # Read old values BEFORE super() — modifications inside super may overwrite them
    old_state = {rec.id: rec.state for rec in self}
    res = super().write(vals)
    if 'state' in vals:
        for rec in self:
            if old_state[rec.id] != rec.state:
                rec._on_state_changed(old_state[rec.id])
    return res

